using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = "";

    [LoadColumn(1)]
    public string Description { get; set; } = "";

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = "";
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = "";

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = "";
    public string Description { get; set; } = "";
    public int Priority { get; set; }
}

public class ClassificationResponse
{
    public string PredictedCategory { get; set; } = "";
    public float Confidence { get; set; }
    public Dictionary<string, float> Scores { get; set; } = new();
}

public class TrainingResponse
{
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public double[] PerClassLogLoss { get; set; } = [];
    public string ConfusionMatrix { get; set; } = "";
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly MLContext _mlContext = new(seed: 42);

    public string[] Labels { get; private set; } = [];

    public ModelTrainingService(string dataPath, string modelPath)
    {
        _dataPath = dataPath;
        _modelPath = modelPath;
    }

    public TrainingResponse TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            path: _dataPath,
            hasHeader: true,
            separatorChar: ',',
            allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);
        var predictions = model.Transform(split.TestSet);

        // Extract label names from Score column slot names
        var scoreColumn = predictions.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _mlContext.Model.Save(model, data.Schema, _modelPath);

        return new TrainingResponse
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassLogLoss = metrics.PerClassLogLoss.ToArray(),
            ConfusionMatrix = metrics.ConfusionMatrix.GetFormattedConfusionTable()
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;
    }

    [HttpPost("classify")]
    public ActionResult<ClassificationResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        var labels = _trainingService.Labels;
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
            scores[labels[i]] = prediction.Score[i];

        return Ok(new ClassificationResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = prediction.Score.Max(),
            Scores = scores
        });
    }

    [HttpPost("train")]
    public ActionResult<TrainingResponse> Train()
    {
        var result = _trainingService.TrainAndEvaluate();
        return Ok(result);
    }
}

