using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

// Train model at startup so evaluation metrics are logged immediately
var trainingService = new ModelTrainingService(dataPath, modelPath);
var metrics = trainingService.TrainAndEvaluate();

Console.WriteLine("=== Model Training Complete ===");
Console.WriteLine($"  Micro Accuracy:     {metrics.MicroAccuracy:F4}");
Console.WriteLine($"  Macro Accuracy:     {metrics.MacroAccuracy:F4}");
Console.WriteLine($"  Log-Loss:           {metrics.LogLoss:F4}");
Console.WriteLine($"  Log-Loss Reduction: {metrics.LogLossReduction:F4}");
Console.WriteLine($"  Confusion Matrix:\n{metrics.ConfusionMatrix}");

builder.Services.AddSingleton(trainingService);

// Thread-safe prediction engine pool (never use singleton PredictionEngine)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath, watchForChanges: true);

var app = builder.Build();
app.MapControllers();
app.Run();

